	local function b64decode(data)
		local b = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
		data = data:gsub("[^" .. b .. "=]", "")
		local result = {}
		local i = 1
		while i <= #data do
			local c1 = b:find(data:sub(i, i), 1, true) - 1
			local c2 = b:find(data:sub(i + 1, i + 1), 1, true) - 1
			local c3 = data:sub(i + 2, i + 2) == "=" and 0 or (b:find(data:sub(i + 2, i + 2), 1, true) - 1)
			local c4 = data:sub(i + 3, i + 3) == "=" and 0 or (b:find(data:sub(i + 3, i + 3), 1, true) - 1)
			local n = c1 * 262144 + c2 * 4096 + c3 * 64 + c4
			result[#result + 1] = string.char(math.floor(n / 65536))
			if data:sub(i + 2, i + 2) ~= "=" then
				result[#result + 1] = string.char(math.floor((n % 65536) / 256))
			end
			if data:sub(i + 3, i + 3) ~= "=" then
				result[#result + 1] = string.char(n % 256)
			end
			i = i + 4
		end
		return table.concat(result)
	end
	for cls, data in pairs(b64) do
		local filepath = ICON_DIR .. cls .. ".png"
		local ok, asset = pcall(function()
			if not pcall(readfile, filepath) then
				writefile(filepath, b64decode(data))
			end
			return getcustomasset(filepath)
		end)
		if ok and asset then
			CLASS_ICONS[cls] = asset
		end
	end
end
buildIconTable()

local _GC_START = collectgarbage("count")
local _TIMESTAMP = os.clock()
local set_ro = setreadonly
	or (make_writeable and function(t, v)
		if v then
			make_readonly(t)
		else
			make_writeable(t)
		end
	end)

local get_mt = getrawmetatable or debug.getmetatable
local hook_meta = hookmetamethod
local new_ccl = newcclosure or function(f)
	return f
end
local check_caller = checkcaller or function()
	return false
end
local clone_func = clonefunction or function(f)
	return f
end

local function dismantle_readonly(target)
	if type(target) ~= "table" then
		return
	end
	pcall(function()
		if set_ro then
			set_ro(target, false)
		end
		local mt = get_mt(target)
		if mt and set_ro then
			set_ro(mt, false)
		end
	end)
end

local nodes = {}
local oldgame = game
local game = workspace.Parent
cloneref = cloneref
	or function(ref)
		if not getreg then
			return ref
		end

		local InstanceList

		local a = Instance.new("Part")
		for _, c in pairs(getreg()) do
			if type(c) == "table" and #c then
				if rawget(c, "__mode") == "kvs" then
					for d, e in pairs(c) do
						if e == a then
							InstanceList = c
							break
						end
					end
				end
			end
		end
		local f = {}
		function f.invalidate(g)
			if not InstanceList then
				return
			end
			for b, c in pairs(InstanceList) do
				if c == g then
					InstanceList[b] = nil
					return g
				end
			end
		end
		return f.invalidate
	end

local _CEShared = _CEShared
	or (function()
		local S = {
			SelectedModule = nil,
			HookedFunctions = {},
			ActivePatches = {},
			FreezeList = {},
			FreezeConn = nil,
			ModuleList = {},
			HookScroll = nil,
			PatchScroll = nil,
			PatchCount = nil,
			Settings = nil,
		}

		local function th()
			local t = S.Settings and S.Settings.Theme
			if t then
				return t
			end
			return {
				Main1 = Color3.fromRGB(30, 32, 38),
				Main2 = Color3.fromRGB(24, 26, 32),
				Outline1 = Color3.fromRGB(18, 19, 24),
				Outline2 = Color3.fromRGB(42, 44, 54),
				Outline3 = Color3.fromRGB(15, 16, 20),
				TextBox = Color3.fromRGB(20, 22, 28),
				Menu = Color3.fromRGB(18, 20, 26),
				Button = Color3.fromRGB(38, 42, 52),
				ButtonHover = Color3.fromRGB(52, 58, 72),
				ButtonPress = Color3.fromRGB(26, 28, 36),
				Highlight = Color3.fromRGB(55, 62, 78),
				Text = Color3.fromRGB(220, 225, 240),
				PlaceholderText = Color3.fromRGB(90, 96, 116),
				ListSelection = Color3.fromRGB(40, 100, 210),
				Important = Color3.fromRGB(255, 70, 70),
			}
		end

		function S:bg()
			return th().Main2
		end
		function S:bg2()
			return th().Main1
		end
		function S:btn_bg()
			return th().Button
		end
		function S:btn_hov()
			return th().ButtonHover
		end
		function S:btn_prs()
			return th().ButtonPress
		end
		function S:outline()
			return th().Outline1
		end
		function S:outline2()
			return th().Outline2
		end
		function S:text()
			return th().Text
		end
		function S:subtext()
			return th().PlaceholderText
		end
		function S:textbox()
			return th().TextBox
		end
		function S:sel()
			return th().ListSelection
		end
		function S:menu()
			return th().Menu
		end
		function S:important()
			return th().Important
		end
		function S:rowA()
			return th().Main2
		end
		function S:rowB()
			return th().Main1
		end
		function S:accent()
			return th().ListSelection
		end
		function S:ok()
			return Color3.fromRGB(80, 200, 80)
		end
		function S:warn()
			return Color3.fromRGB(255, 165, 0)
		end
		function S:err()
			return Color3.fromRGB(255, 80, 80)
		end

		function S:border(parent, inset)
			local tc = inset and self:outline() or self:outline2()
			local bc = inset and self:outline2() or self:outline()
			local function mk(n, sz, pos, c)
				local f = Instance.new("Frame", parent)
				f.Name = n
				f.Size = sz
				f.Position = pos
				f.BackgroundColor3 = c
				f.BorderSizePixel = 0
				f.ZIndex = parent.ZIndex + 1
			end
			mk("BT", UDim2.new(1, 0, 0, 1), UDim2.new(0, 0, 0, 0), tc)
			mk("BL", UDim2.new(0, 1, 1, 0), UDim2.new(0, 0, 0, 0), tc)
			mk("BB", UDim2.new(1, 0, 0, 1), UDim2.new(0, 0, 1, -1), bc)
			mk("BR", UDim2.new(0, 1, 1, 0), UDim2.new(1, -1, 0, 0), bc)
		end

		function S:btn(parent, text, size, pos, cb)
			local b = Instance.new("TextButton", parent)
			b.Size = size
			b.Position = pos
			b.BackgroundColor3 = self:btn_bg()
			b.Text = text
			b.TextColor3 = self:text()
			b.Font = Enum.Font.SourceSans
			b.TextSize = 12
			b.BorderSizePixel = 0
			b.AutoButtonColor = false
			b.ClipsDescendants = true
			self:border(b, false)
			if cb then
				b.MouseButton1Click:Connect(cb)
			end
			b.MouseButton1Down:Connect(function()
				b.BackgroundColor3 = self:btn_prs()
			end)
			b.MouseButton1Up:Connect(function()
				b.BackgroundColor3 = self:btn_bg()
			end)
			b.MouseEnter:Connect(function()
				if b.BackgroundColor3 ~= self:btn_prs() then
					game:GetService("TweenService")
						:Create(b, TweenInfo.new(0.08), { BackgroundColor3 = self:btn_hov() })
						:Play()
				end
			end)
			b.MouseLeave:Connect(function()
				if b.BackgroundColor3 ~= self:btn_prs() then
					game:GetService("TweenService")
						:Create(b, TweenInfo.new(0.08), { BackgroundColor3 = self:btn_bg() })
						:Play()
				end
			end)
			return b
		end

		function S:scroll(parent, size, pos, dark)
			local f = Instance.new("ScrollingFrame", parent)
			f.Size = size
			f.Position = pos
			f.BackgroundColor3 = dark and Color3.fromRGB(18, 18, 18) or self:bg()
			f.BorderSizePixel = 0
			f.ScrollBarThickness = 8
			f.ScrollBarImageColor3 = self:accent()
			f.AutomaticCanvasSize = Enum.AutomaticSize.Y
			f.CanvasSize = UDim2.new(0, 0, 0, 0)
			self:border(f, true)
			local l = Instance.new("UIListLayout", f)
			l.Padding = UDim.new(0, 1)
			return f
		end

		function S:input(parent, size, pos, placeholder)
			local b = Instance.new("TextBox", parent)
			b.Size = size
			b.Position = pos
			b.BackgroundColor3 = self:textbox()
			b.PlaceholderText = placeholder or ""
			b.PlaceholderColor3 = self:subtext()
			b.Text = ""
			b.TextColor3 = self:text()
			b.Font = Enum.Font.Code
			b.TextSize = 11
			b.ClearTextOnFocus = false
			b.BorderSizePixel = 0
			b.TextXAlignment = Enum.TextXAlignment.Left
			self:border(b, true)
			local p = Instance.new("UIPadding", b)
			p.PaddingLeft = UDim.new(0, 4)
			return b
		end

		function S:lbl(parent, text, size, pos, sub)
			local l = Instance.new("TextLabel", parent)
			l.Size = size
			l.Position = pos
			l.BackgroundTransparency = 1
			l.Text = text
			l.TextColor3 = sub and self:subtext() or self:text()
			l.Font = Enum.Font.SourceSans
			l.TextSize = 11
			l.TextXAlignment = Enum.TextXAlignment.Left
			return l
		end

		function S:panel(parent, size, pos)
			local f = Instance.new("Frame", parent)
			f.Size = size
			f.Position = pos
			f.BackgroundColor3 = self:bg2()
			f.BorderSizePixel = 0
			self:border(f, false)
			return f
		end

		function S:addRow(scroll, text, bg, textColor, rowH)
			rowH = rowH or 16
			local row = Instance.new("Frame", scroll)
			row.Size = UDim2.new(1, 0, 0, rowH)
			row.BackgroundColor3 = bg or self:rowA()
			row.BorderSizePixel = 0
			local lb = Instance.new("TextLabel", row)
			lb.Size = UDim2.new(1, -4, 1, 0)
			lb.Position = UDim2.fromOffset(4, 0)
			lb.BackgroundTransparency = 1
			lb.Text = text
			lb.TextColor3 = textColor or self:text()
			lb.Font = Enum.Font.Code
			lb.TextSize = 11
			lb.TextXAlignment = Enum.TextXAlignment.Left
			lb.TextTruncate = Enum.TextTruncate.AtEnd
			return row, lb
		end

		function S:clip(txt)
			if setclipboard then
				setclipboard(txt)
			elseif toclipboard then
				toclipboard(txt)
			end
		end

		function S:uid()
			local c = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
			local r = ""
			for i = 1, 12 do
				r = r .. c:sub(math.random(1, #c), math.random(1, #c))
			end
			return r
		end

		function S:tableLen(t)
			local n = 0
			for _ in pairs(t) do
				n = n + 1
			end
			return n
		end

		function S:prettyArg(v, d)
			d = d or 0
			if d > 3 then
				return "..."
			end
			local t = type(v)
			if t == "nil" then
				return "nil"
			elseif t == "boolean" or t == "number" then
				return tostring(v)
			elseif t == "string" then
				return '"' .. v:sub(1, 60) .. '"'
			elseif t == "function" then
				return "fn@" .. tostring(v):sub(-6)
			elseif t == "table" then
				local parts, n = {}, 0
				for k, val in pairs(v) do
					n = n + 1
					if n > 6 then
						table.insert(parts, "...")
						break
					end
					table.insert(parts, tostring(k) .. "=" .. self:prettyArg(val, d + 1))
				end
				return "{" .. table.concat(parts, ", ") .. "}"
			else
				if typeof then
					local ty = typeof(v)
					if ty == "Vector3" then
						return string.format("V3(%.2f,%.2f,%.2f)", v.X, v.Y, v.Z)
					elseif ty == "CFrame" then
						return string.format("CF(%.1f,%.1f,%.1f)", v.X, v.Y, v.Z)
					elseif ty == "Instance" then
						return "[" .. v.ClassName .. " " .. v.Name .. "]"
					elseif ty == "Color3" then
						return string.format("C3(%d,%d,%d)", v.R * 255, v.G * 255, v.B * 255)
					end
				end
				return tostring(v):sub(1, 40)
			end
		end

		function S:startFreezeLoop()
			if self.FreezeConn then
				return
			end
			self.FreezeConn = game:GetService("RunService").Heartbeat:Connect(function()
				for id, patch in pairs(self.FreezeList) do
					pcall(function()
						if setreadonly then
							setreadonly(patch.Table, false)
						elseif make_writeable then
							make_writeable(patch.Table)
						end
						rawset(patch.Table, patch.Key, patch.NewValue)
						if setreadonly then
							setreadonly(patch.Table, true)
						end
					end)
				end
			end)
		end

		function S:getRawMt(tbl)
			return (getrawmetatable or debug and debug.getmetatable or getmetatable)(tbl)
		end

		_G._CEShared = S
		return S
	end)()

_G._CEShared.quickHook = function(self, func, parentTable, key, hookType, customValue)
	if type(func) ~= "function" then
		warn("[CEShared] quickHook: not a function")
		return
	end
	if not hookfunction then
		warn("[CEShared] quickHook: hookfunction unavailable")
		return
	end
	local hookId = self:uid()
	local originalFunc = func
	local hookFunc
	local hookTypes = {
		return_true = function()
			return true
		end,
		return_false = function()
			return false
		end,
		return_nil = function()
			return nil
		end,
		return_zero = function()
			return 0
		end,
		return_one = function()
			return 1
		end,
		return_empty_table = function()
			return {}
		end,
		return_empty_string = function()
			return ""
		end,
		block = function() end,
		log_passthrough = function(...)
			local rets = { originalFunc(...) }
			print("[QuickHook]", key, "args:", ..., "→", table.unpack(rets))
			return table.unpack(rets)
		end,
		custom = function()
			return customValue
		end,
	}
	hookFunc = hookTypes[hookType] or hookTypes.log_passthrough
	pcall(function()
		if setreadonly then
			setreadonly(parentTable, false)
		elseif make_writeable then
			make_writeable(parentTable)
		end
	end)
	rawset(parentTable, key, hookFunc)
	pcall(function()
		if setreadonly then
			setreadonly(parentTable, true)
		end
	end)
	self.HookedFunctions[hookId] = {
		ID = hookId,
		Table = parentTable,
		Key = key,
		Original = originalFunc,
		HookFunction = hookFunc,
		HookType = hookType,
		CustomValue = customValue,
		Enabled = true,
		CallCount = 0,
		Timestamp = tick(),
	}
	self.ActivePatches[hookId] = {
		ID = hookId,
		Table = parentTable,
		Key = key,
		Original = originalFunc,
		NewValue = hookFunc,
		Type = "function_hook",
		Frozen = false,
		Timestamp = tick(),
		Active = true,
	}
	if self.RefreshHooks then
		self:RefreshHooks()
	end
	if self.RefreshPatches then
		self:RefreshPatches()
	end
	return hookId
end

