			G2L["1e"]["Text"] = [[Auto Scroll]]

			G2L["1f"] = Instance.new("UIPadding", G2L["20"])
			G2L["1f"]["PaddingTop"] = UDim.new(0, 1)
			G2L["1f"]["PaddingBottom"] = UDim.new(0, 1)

