				context:Register("TABLE_INSPECTOR", {
					Name = "Table Edit [RE]",
					IconMap = Explorer.MiscIcons,
					Icon = "ExploreData",
					OnClick = function()
						local node = selection.List[1]
						if not node then
							return
						end
						local obj = node.Obj
						local getgcf = env.getgc or getgc or get_gc_objects
						local getfenv_ = getfenv
						local rootTable = nil
						local rootLabel = "?"

						if
							pcall(function()
								return obj:IsA("LuaSourceContainer")
							end) and obj:IsA("LuaSourceContainer")
						then
							if getgcf then
								local ok, gc = pcall(getgcf)
								if ok and gc then
									for _, fn in pairs(gc) do
										if type(fn) == "function" then
											local ok2, fenv = pcall(getfenv_, fn)
											if
												ok2
												and fenv
												and (
													rawget(fenv, "script") == obj
													or (type(fenv) == "table" and fenv.script == obj)
												)
											then
												rootTable = fenv
												rootLabel = "fenv of " .. obj.Name
												break
											end
										end
									end
								end
							end
							if not rootTable then
								if
									pcall(function()
										return obj:IsA("ModuleScript")
									end) and obj:IsA("ModuleScript")
								then
									local ok, res = pcall(require, obj)
									if ok and type(res) == "table" then
										rootTable = res
										rootLabel = "require(" .. obj.Name .. ")"
									elseif ok and res ~= nil then
										rootTable = { ["[value]"] = res, ["[type]"] = type(res) }
										rootLabel = "require(" .. obj.Name .. ")[wrapped:" .. type(res) .. "]"
									else
										local getgcf = env and env.getgc
											or (pcall(function()
												return getgc
											end) and getgc)
										if getgcf then
											local gcok, gc = pcall(getgcf)
											if gcok and gc then
												for _, fn in pairs(gc) do
													if type(fn) == "function" then
														local fok, fenv = pcall(getfenv, fn)
														if
															fok
															and fenv
															and (rawget(fenv, "script") == obj or fenv.script == obj)
														then
															rootTable = fenv
															rootLabel = "getfenv(" .. obj.Name .. ")"
															break
														end
													end
												end
											end
										end
									end
								end
							end
							if not rootTable then
								if getgenv().DoNotif then
									getgenv().DoNotif(" No table found for: " .. obj.Name, 2)
								end
								return
							end
						else
							rootTable = getfenv_() or {}
							rootLabel = "_G (local env)"
						end

						local activePatches = {}
						local valueHooks = {}
						local hookedConns = {}

						local function _getRawMt(tbl)
							if getrawmetatable then
								local ok, mt = pcall(getrawmetatable, tbl)
								return ok and mt or nil
							end
							return getmetatable(tbl)
						end

						local function _unlock(t)
							pcall(function()
								if setreadonly then
									setreadonly(t, false)
								elseif make_writeable then
									make_writeable(t)
								end
							end)
						end
						local function _lock(t)
							pcall(function()
								if setreadonly then
									setreadonly(t, true)
								end
							end)
						end

						local function applyPatch(tbl, key, val, isFunc)
							if type(tbl) ~= "table" then
								return false
							end
							if not activePatches[tbl] then
								activePatches[tbl] = {}
							end
							activePatches[tbl][key] = { Value = val, Locked = true, IsFunction = isFunc }
							pcall(function()
								_unlock(tbl)
								if isFunc then
									if val == "TRUE" then
										rawset(tbl, key, function()
											return true
										end)
									elseif val == "FALSE" then
										rawset(tbl, key, function()
											return false
										end)
									else
										rawset(tbl, key, val)
									end
								else
									rawset(tbl, key, val)
								end
								_lock(tbl)
							end)
							local mt = _getRawMt(tbl)
							if mt then
								pcall(function()
									_unlock(mt)
									local oldIdx = rawget(mt, "__index")
									rawset(mt, "__index", function(t, k)
										if k == key then
											return val
										elseif type(oldIdx) == "function" then
											return oldIdx(t, k)
										elseif type(oldIdx) == "table" then
											return oldIdx[k]
										end
									end)
									_lock(mt)
								end)
							end
							return true
						end

						local function hookValue(tbl, key, value)
							local hk = tostring(tbl) .. ":" .. tostring(key)
							if valueHooks[hk] then
								valueHooks[hk].enabled = true
								return
							end
							valueHooks[hk] = { table = tbl, key = key, value = value, enabled = true }
							pcall(function()
								_unlock(tbl)
								rawset(tbl, key, value)
								_lock(tbl)
							end)
							local mt = _getRawMt(tbl)
							if mt then
								pcall(function()
									_unlock(mt)
									local origNI = rawget(mt, "__newindex")
									rawset(mt, "__newindex", function(t, k, v)
										if k == key then
											rawset(tbl, key, value)
										elseif type(origNI) == "function" then
											origNI(t, k, v)
										else
											rawset(t, k, v)
										end
									end)
									_lock(mt)
								end)
							end
							hookedConns[hk] = game:GetService("RunService").Heartbeat:Connect(function()
								if valueHooks[hk] and valueHooks[hk].enabled then
									pcall(function()
										if rawget(tbl, key) ~= value then
											rawset(tbl, key, value)
										end
									end)
								end
							end)
						end

						local function unhookValue(tbl, key)
							local hk = tostring(tbl) .. ":" .. tostring(key)
							valueHooks[hk] = nil
							if hookedConns[hk] then
								pcall(function()
									hookedConns[hk]:Disconnect()
								end)
								hookedConns[hk] = nil
							end
						end

						local function getUpvalues(func, depth, maxDepth)
							depth = depth or 0
							maxDepth = maxDepth or 5
							if depth > maxDepth then
								return {}
							end
							local uvs = {}
							local ok, result = pcall(debug.getupvalues, func)
							if ok and result then
								for i, uv in ipairs(result) do
									local t = type(uv)
									uvs[i] = {
										Index = i,
										Value = uv,
										Type = t,
										IsFunction = t == "function",
										IsTable = t == "table",
										ChildUpvalues = (t == "function") and getUpvalues(uv, depth + 1, maxDepth)
											or {},
									}
								end
							end
							return uvs
						end

						local function patchUpvalue(func, idx, newVal)
							pcall(debug.setupvalue, func, idx, newVal)
						end

						local function getPatchCount()
							local n = 0
							for _ in pairs(activePatches) do
								n = n + 1
							end
							return n
						end

						local function parseValue(text, vtype)
							if vtype == "boolean" then
								if text == "true" then
									return true
								elseif text == "false" then
									return false
								else
									return nil
								end
							elseif vtype == "number" then
								return tonumber(text)
							else
								return text
							end
						end

						local frozenConns = {}

						local function freezePatch(tbl, key, val, row)
							local hk = tostring(tbl) .. ":FRZ:" .. tostring(key)
							if frozenConns[hk] then
								pcall(function()
									frozenConns[hk]:Disconnect()
								end)
								frozenConns[hk] = nil
							end
							if not activePatches[tbl] then
								activePatches[tbl] = {}
							end
							activePatches[tbl][key] = { Value = val, Locked = true, IsFunction = false, Frozen = true }
							pcall(function()
								_unlock(tbl)
								rawset(tbl, key, val)
								_lock(tbl)
							end)
							frozenConns[hk] = game:GetService("RunService").Heartbeat:Connect(function()
								local patch = activePatches[tbl] and activePatches[tbl][key]
								if patch and patch.Frozen then
									pcall(function()
										if rawget(tbl, key) ~= val then
											_unlock(tbl)
											rawset(tbl, key, val)
											_lock(tbl)
										end
									end)
								else
									pcall(function()
										frozenConns[hk]:Disconnect()
									end)
									frozenConns[hk] = nil
								end
							end)
							if row and row.Parent then
								row.BackgroundColor3 = Color3.fromRGB(255, 200, 200)
								row.BackgroundTransparency = 0
							end
						end

						local function unfreezeKey(tbl, key, row)
							local hk = tostring(tbl) .. ":FRZ:" .. tostring(key)
							if frozenConns[hk] then
								pcall(function()
									frozenConns[hk]:Disconnect()
								end)
								frozenConns[hk] = nil
							end
							if activePatches[tbl] then
								activePatches[tbl][key] = nil
							end
							if row and row.Parent then
								row.BackgroundTransparency = 1
							end
						end

						local function analyzeMetatableChain(tbl, depth, visited)
							depth = depth or 1
							visited = visited or {}
							if depth > 8 then
								return {}
							end

							local mt = _getRawMt(tbl)
							if not mt or type(mt) ~= "table" then
								return {}
							end
							if visited[mt] then
								return {}
							end
							visited[mt] = true

							local locked = false
							pcall(function()
								if isreadonly then
									locked = isreadonly(mt)
								elseif make_writeable then
									local ok = pcall(function()
										local dummy = {}
										setmetatable(dummy, mt)
									end)
									locked = not ok
								end
							end)

							local fields = {}
							local ok = pcall(function()
								for k, v in pairs(mt) do
									table.insert(fields, { Key = k, Value = v })
								end
							end)

							local entry = {
								Metatable = mt,
								Depth = depth,
								Locked = locked,
								Fields = fields,
								AccessMethod = ok and "pairs()" or "protected",
							}

							local chain = { entry }
							local idx = rawget(mt, "__index")
							if type(idx) == "table" and not visited[idx] then
								local sub = analyzeMetatableChain(idx, depth + 1, visited)
								for _, s in ipairs(sub) do
									table.insert(chain, s)
								end
							end
							return chain
						end

						local function getModuleContent(obj)
							local ok, result = pcall(require, obj)
							if ok then
								if type(result) == "table" then
									return result, "require"
								elseif result ~= nil then
									return { ["[value]"] = result, ["[type]"] = type(result) }, "require(wrapped)"
								end
							end
							local getgcf = env and env.getgc
								or (pcall(function()
									return getgc
								end) and getgc)
							if getgcf then
								local gcok, gc = pcall(getgcf)
								if gcok and gc then
									for _, fn in pairs(gc) do
										if type(fn) == "function" then
											local fok, fenv = pcall(getfenv, fn)
											if
												fok
												and fenv
												and (rawget(fenv, "script") == obj or fenv.script == obj)
											then
												return fenv, "getfenv"
											end
										end
									end
								end
							end
							return nil, "failed"
						end

