								box.FocusLost:Connect(function(entered)
									if entered then
										local newVal = parseValue(box.Text, vt)
										if newVal ~= nil then
											applyPatch(tbl, k, newVal, false)
											box.Text = tostring(newVal)
											statusLabel.Text = "Patched: " .. ks .. " = " .. tostring(newVal)
											updateTitle()
										end
									end
								end)
								if vt == "number" then
									local hookBtn = Instance.new("TextButton", row)
									hookBtn.Size = UDim2.new(0, 40, 0, 24)
									hookBtn.Position = UDim2.fromScale(0.53, 0.14)
									hookBtn.BackgroundColor3 = Color3.fromRGB(20, 50, 30)
									hookBtn.Text = "HOOK"
									hookBtn.TextColor3 = Color3.fromRGB(0, 200, 150)
									hookBtn.Font = Enum.Font.Code
									hookBtn.TextSize = 7
									Instance.new("UICorner", hookBtn).CornerRadius = UDim.new(0, 2)
									hookBtn.MouseButton1Click:Connect(function()
										local nv = tonumber(box.Text) or v
										hookValue(tbl, k, nv)
										hookBtn.BackgroundColor3 = Color3.fromRGB(0, 120, 80)
										hookBtn.Text = "LOCKED"
										statusLabel.Text = "Hooked: " .. ks
										task.delay(1, function()
											hookBtn.BackgroundColor3 = Color3.fromRGB(20, 50, 30)
											hookBtn.Text = "HOOK"
										end)
									end)
									local unhookBtn = Instance.new("TextButton", row)
									unhookBtn.Size = UDim2.new(0, 40, 0, 24)
									unhookBtn.Position = UDim2.fromScale(0.62, 0.14)
									unhookBtn.BackgroundColor3 = Color3.fromRGB(50, 20, 20)
									unhookBtn.Text = "UNHK"
									unhookBtn.TextColor3 = Color3.fromRGB(255, 100, 100)
									unhookBtn.Font = Enum.Font.Code
									unhookBtn.TextSize = 7
									Instance.new("UICorner", unhookBtn).CornerRadius = UDim.new(0, 2)
									unhookBtn.MouseButton1Click:Connect(function()
										unhookValue(tbl, k)
										statusLabel.Text = "Unhooked: " .. ks
									end)
								end
								local frzBtn = Instance.new("TextButton", row)
								frzBtn.Size = UDim2.new(0, 34, 0, 24)
								frzBtn.Position = UDim2.fromScale(vt == "number" and 0.73 or 0.53, 0.14)
								frzBtn.BackgroundColor3 = Color3.fromRGB(30, 30, 80)
								frzBtn.Text = "FRZ"
								frzBtn.TextColor3 = Color3.fromRGB(150, 180, 255)
								frzBtn.Font = Enum.Font.Code
								frzBtn.TextSize = 7
								Instance.new("UICorner", frzBtn).CornerRadius = UDim.new(0, 2)
								frzBtn.MouseButton1Click:Connect(function()
									local nv = parseValue(box.Text, vt)
									if nv ~= nil then
										freezePatch(tbl, k, nv, row)
										frzBtn.BackgroundColor3 = Color3.fromRGB(0, 80, 200)
										frzBtn.Text = "FRZ"
										statusLabel.Text = "Frozen: " .. ks .. " = " .. tostring(nv)
										updateTitle()
									end
								end)
								local unfrzBtn = Instance.new("TextButton", row)
								unfrzBtn.Size = UDim2.new(0, 34, 0, 24)
								unfrzBtn.Position = UDim2.fromScale(vt == "number" and 0.80 or 0.60, 0.14)
								unfrzBtn.BackgroundColor3 = Color3.fromRGB(80, 20, 20)
								unfrzBtn.Text = "UFRZ"
								unfrzBtn.TextColor3 = Color3.fromRGB(255, 120, 120)
								unfrzBtn.Font = Enum.Font.Code
								unfrzBtn.TextSize = 7
								Instance.new("UICorner", unfrzBtn).CornerRadius = UDim.new(0, 2)
								unfrzBtn.MouseButton1Click:Connect(function()
									unfreezeKey(tbl, k, row)
									frzBtn.BackgroundColor3 = Color3.fromRGB(30, 30, 80)
									frzBtn.Text = "FRZ"
									statusLabel.Text = "Unfrozen: " .. ks
									updateTitle()
								end)
								local setclip = (env and env.setclipboard)
									or (pcall(function()
										return setclipboard
									end) and setclipboard)
									or nil
