									copyBtn.Size = UDim2.new(0, 26, 0, 24)
									copyBtn.Position = UDim2.fromScale(0.72, 0.14)
									copyBtn.BackgroundColor3 = Color3.fromRGB(30, 30, 50)
									copyBtn.Text = "CP"
									copyBtn.TextColor3 = Color3.fromRGB(150, 180, 255)
									copyBtn.Font = Enum.Font.Code
