				context:Register("ATTACH_BEHIND", {
					Name = "Attach Behind",
					IconMap = Explorer.MiscIcons,
					Icon = "TeleportTo",
					OnClick = function()
						local sList = selection.List
						if #sList == 0 then
							return
						end

						local function getRootPart(obj)
							if obj:IsA("BasePart") then
								return obj
							end
							if obj:IsA("Model") then
								if obj.PrimaryPart then
									return obj.PrimaryPart
								end
								local hrp = obj:FindFirstChild("HumanoidRootPart")
								if hrp then
									return hrp
								end
								return obj:FindFirstChildWhichIsA("BasePart", true)
							end
							if obj:IsA("Humanoid") then
								local model = obj.Parent
								if model and model:IsA("Model") then
									if model.PrimaryPart then
										return model.PrimaryPart
									end
									local hrp = model:FindFirstChild("HumanoidRootPart")
									if hrp then
										return hrp
									end
									return model:FindFirstChildWhichIsA("BasePart", true)
								end
							end
							return nil
						end

						local targetRoot = getRootPart(sList[1].Obj)
						if not targetRoot then
							if getgenv().DoNotif then
								getgenv().DoNotif("Attach Behind: no root part found", 2)
							end
							return
						end

						if _G._zexAttachConn then
							pcall(function()
								_G._zexAttachConn:Disconnect()
							end)
							_G._zexAttachConn = nil
						end

						local RunService = game:GetService("RunService")
						local OFFSET = CFrame.new(0, 0, 4)

						_G._zexAttachTarget = targetRoot
						_G._zexAttachConn = RunService.Heartbeat:Connect(function()
							local myChar = plr.Character
							local myHRP = myChar and myChar:FindFirstChild("HumanoidRootPart")
							if not myHRP or not targetRoot or not targetRoot.Parent then
								if _G._zexAttachConn then
									_G._zexAttachConn:Disconnect()
									_G._zexAttachConn = nil
									_G._zexAttachTarget = nil
								end
								return
							end
							pcall(function()
								myHRP.CFrame = targetRoot.CFrame * OFFSET
							end)
						end)

						if getgenv().DoNotif then
							getgenv().DoNotif("Attach Behind: ON → " .. targetRoot:GetFullName(), 3)
						end
					end,
				})

				context:Register("DETACH_BEHIND", {
					Name = "Detach Behind",
					IconMap = Explorer.MiscIcons,
					Icon = "Delete",
					OnClick = function()
						if _G._zexAttachConn then
							pcall(function()
								_G._zexAttachConn:Disconnect()
							end)
							_G._zexAttachConn = nil
							_G._zexAttachTarget = nil
							if getgenv().DoNotif then
								getgenv().DoNotif("Attach Behind: OFF", 2)
							end
						else
							if getgenv().DoNotif then
								getgenv().DoNotif("Attach Behind: already off", 2)
							end
						end
					end,
				})

				context:Register("HUMAN_SHIELD_BRING", {
					Name = "Shield: Bring",
					IconMap = Explorer.MiscIcons,
					Icon = "SelectChildren",
					OnClick = function()
						local node = selection.List[1]
						if not node then
							return
						end
						local obj = node.Obj
						if not obj:IsA("Player") or obj == plr then
							if getgenv().DoNotif then
								getgenv().DoNotif("Select another player", 2)
							end
							return
						end

						local myChar = plr.Character
						local myRoot = myChar and myChar:FindFirstChild("HumanoidRootPart")
						if not myRoot then
							if getgenv().DoNotif then
								getgenv().DoNotif("Your character not found", 2)
							end
							return
						end

						local DISTANCE = 4.5
						local VERT_OFFSET = 0
						local LERP_SPEED = 0.2

						local connId = "_shieldConn_" .. obj.UserId
						if _G[connId] then
							pcall(function()
								_G[connId]:Disconnect()
							end)
							_G[connId] = nil
						end

						local function setupBring(character)
							local tRoot = character and character:FindFirstChild("HumanoidRootPart")
							if not tRoot then
								return
							end

							if _G[connId] then
								pcall(function()
									_G[connId]:Disconnect()
								end)
							end

							_G[connId] = game:GetService("RunService").Heartbeat:Connect(function(dt)
								local myC = plr.Character
								local myR = myC and myC:FindFirstChild("HumanoidRootPart")
								if not (myR and tRoot and tRoot.Parent) then
									return
								end
								pcall(function()
									local target = myR.CFrame * CFrame.new(0, VERT_OFFSET, -DISTANCE)
									local alpha = 1 - (1 - LERP_SPEED) ^ (dt * 60)
									tRoot.CFrame = tRoot.CFrame:Lerp(target, alpha)
									tRoot.AssemblyLinearVelocity = Vector3.zero
									tRoot.AssemblyAngularVelocity = Vector3.zero
								end)
							end)
						end

						setupBring(obj.Character)

						local respawnId = "_shieldRespawn_" .. obj.UserId
						if _G[respawnId] then
							pcall(function()
								_G[respawnId]:Disconnect()
							end)
						end
						_G[respawnId] = obj.CharacterAdded:Connect(function(char)
							task.wait(0.1)
							setupBring(char)
							if getgenv().DoNotif then
								getgenv().DoNotif(obj.Name .. " respawned - re-bringing", 1.5)
							end
						end)

						if getgenv().DoNotif then
							getgenv().DoNotif("Shield: bringing " .. obj.Name, 2)
						end
					end,
				})

