				context:Register("ANTIAIM_TOGGLE", {
					Name = "AntiAim: Toggle",
					IconMap = Explorer.MiscIcons,
					Icon = "Play",
					OnClick = function()
						local char = plr.Character
						local hrp = char and char:FindFirstChild("HumanoidRootPart")
						if not hrp then
							return
						end

						if _G._aaConn then
							pcall(function()
								_G._aaConn:Disconnect()
							end)
							_G._aaConn = nil
							pcall(function()
								_G._aaRSConn:Disconnect()
							end)
							_G._aaRSConn = nil
							pcall(function()
								hrp.AssemblyLinearVelocity = Vector3.new(0, 0, 0)
								hrp.AssemblyAngularVelocity = Vector3.new(0, 0, 0)
							end)
							if getgenv().DoNotif then
								getgenv().DoNotif("AntiAim: OFF", 2)
							end
						else
							local patternStart = tick()
							local currentPattern = nil
							local strength = 80

							local patterns = {
								function(t)
									return Vector3.new(
										math.cos(t * 10) * strength,
										math.sin(t * 5) * strength,
										math.sin(t * 10) * strength
									)
								end,
								function(t)
									return Vector3.new(
										math.sin(t * 8) * strength,
										math.cos(t * 4) * strength * 0.5,
										math.sin(t * 4) * math.cos(t * 4) * strength
									)
								end,
								function(t)
									local noise = math.noise(t * 20, t * 15, t * 10) or 0.5
									return Vector3.new(
										math.random(-100, 100) * noise,
										math.random(-100, 100) * noise,
										math.random(-100, 100) * noise
									).Unit * strength
								end,
								function(t)
									local dirs = {
										Vector3.new(1, 0, 0),
										Vector3.new(-1, 0, 0),
										Vector3.new(0, 1, 0),
										Vector3.new(0, -1, 0),
										Vector3.new(0, 0, 1),
										Vector3.new(0, 0, -1),
									}
									return dirs[math.floor(t * 30) % 6 + 1] * strength
								end,
								function(t)
									local a = t * 15
									return Vector3.new(
										math.cos(a) * strength,
										math.random(-1, 1) * strength * 0.3,
										math.sin(a) * strength
									)
								end,
							}

							local oldCFrame, oldVelocity
							_G._aaConn = game:GetService("RunService").Heartbeat:Connect(function()
								local root = plr.Character and plr.Character:FindFirstChild("HumanoidRootPart")
								if not root then
									return
								end
								oldCFrame = root.CFrame
								oldVelocity = root.AssemblyLinearVelocity
								if not currentPattern or math.random() < 0.15 then
									currentPattern = patterns[math.random(1, #patterns)]
									patternStart = tick()
								end
								local vec = currentPattern(tick() - patternStart)
								pcall(function()
									root.CFrame = root.CFrame + vec
									root.AssemblyLinearVelocity = vec
								end)
							end)

							_G._aaRSConn = game:GetService("RunService").RenderStepped:Connect(function()
								local root = plr.Character and plr.Character:FindFirstChild("HumanoidRootPart")
								if not root or not oldCFrame then
									return
								end
								pcall(function()
									root.CFrame = oldCFrame
									root.AssemblyLinearVelocity = oldVelocity
								end)
							end)

							if getgenv().DoNotif then
								getgenv().DoNotif("AntiAim: ON", 2)
							end
						end
					end,
				})

				context:Register("ANTIAIM_RESTORE_VELOCITY", {
					Name = "AntiAim: Kill Velocity",
					IconMap = Explorer.MiscIcons,
					Icon = "Stop",
					OnClick = function()
						local char = plr.Character
						local hrp = char and char:FindFirstChild("HumanoidRootPart")
						if _G._aaConn then
							pcall(function()
								_G._aaConn:Disconnect()
							end)
							_G._aaConn = nil
						end
						if _G._aaRSConn then
							pcall(function()
