					nodes[nilNode.Obj] = nilNode
				end

				Explorer.SetupConnections()

				local insts = getDescendants(game)
				if Main.Elevated then
					for i = 1, #insts do
						local obj = insts[i]
						local par = nodes[ffa(obj, "Instance")]
						if not par then
							continue
						end
						local newNode = {
							Obj = obj,
							Parent = par,
						}
						nodes[obj] = newNode
						par[#par + 1] = newNode
					end
				else
					for i = 1, #insts do
						local obj = insts[i]
						local s, parObj = pcall(ffa, obj, "Instance")
						local par = nodes[parObj]
						if not par then
							continue
						end
						local newNode = {
							Obj = obj,
							Parent = par,
						}
						nodes[obj] = newNode
						par[#par + 1] = newNode
					end
				end
			end

			return Explorer
		end

