						self.GuiElems.Title.TextXAlignment = 2
						self.GuiElems.Title.Size = UDim2.new(1, -20, 0, 20)
					end

					if Settings.Window.Transparency then
						self.GuiElems.Content.BackgroundTransparency = Settings.Window.Transparency
