					envelopeDragLine.BackgroundColor3 = Color3.new(0, 0, 0)
					envelopeDragLine.BorderSizePixel = 0
					envelopeDragLine.Position = UDim2.new(0, 3, 0, 0)
					envelopeDragLine.Size = UDim2.new(0, 1, 0, 20)
