			local Infect
			local function buildEnv(scriptObj)
				local e = {
					script = scriptObj,
					game = MockGame,
					Game = MockGame,
					workspace = workspace,
					Workspace = workspace,
					owner = LocalPlayer,
					RunService = MockRunService,
					Instance = MockInstance,
