					bit32 = bit32,
					utf8 = utf8,
					task = task,
					delay = delay,
					spawn = spawn,
					wait = wait,
					tick = tick,
					time = time,
					Vector2 = Vector2,
					Vector3 = Vector3,
					CFrame = CFrame,
					Color3 = Color3,
