					"workspace",
					"script",
					"plugin",
					"settings",
					"shared",
					"UserSettings",
					"print",
					"warn",
					"error",
					"assert",
					"pcall",
					"xpcall",
					"require",
					"select",
					"pairs",
					"ipairs",
					"next",
					"unpack",
					"type",
					"typeof",
					"tostring",
					"tonumber",
					"setmetatable",
					"getmetatable",
					"rawset",
					"rawget",
					"rawequal",
					"rawlen",
					"math",
					"table",
