									return
								end
								local rawFlags = type(flags) == "number" and flags or 0
								local df = {}
								if proto.main then
									df.native = toBoolean(bit32.band(rawFlags, LuauProtoFlag.LPF_NATIVE_MODULE))
								else
									df.native = toBoolean(bit32.band(rawFlags, LuauProtoFlag.LPF_NATIVE_FUNCTION))
