									local opn = oci.name
									local opt = oci.type
									local isAux = oci.aux == true
									local A, B, C, sD, D, E, aux
									if opt == "A" then
										A = Luau:INSN_A(instruction)
									elseif opt == "E" then
										E = Luau:INSN_E(instruction)
									elseif opt == "AB" then
										A = Luau:INSN_A(instruction)
										B = Luau:INSN_B(instruction)
									elseif opt == "AC" then
										A = Luau:INSN_A(instruction)
										C = Luau:INSN_C(instruction)
									elseif opt == "ABC" then
										A = Luau:INSN_A(instruction)
										B = Luau:INSN_B(instruction)
										C = Luau:INSN_C(instruction)
									elseif opt == "AD" then
										A = Luau:INSN_A(instruction)
										D = Luau:INSN_D(instruction)
									elseif opt == "AsD" then
										A = Luau:INSN_A(instruction)
										sD = Luau:INSN_sD(instruction)
									elseif opt == "sD" then
