			local function resolvePatchTarget()
				local rawPath = tablePathBox.Text
				local key = keyBox.Text
				if key == "" then
					return nil, nil, "Key cannot be empty"
				end

				if rawPath == "" then
					if selectedPatchRef then
						return selectedPatchRef.Table, key, nil
					end
					if not S.SelectedModule then
						return nil, nil, "No row selected and no module selected in Explorer"
					end
					local ok, mod = pcall(require, S.SelectedModule)
					if not ok or type(mod) ~= "table" then
						return nil, nil, "SelectedModule did not return a table"
					end
					return mod, key, nil
				end

				local path = rawPath:match("^_G%.(.+)$") or rawPath:match("^_G$") and "" or rawPath

				local parts = {}
				for seg in path:gmatch("[^%.]+") do
					table.insert(parts, seg)
				end

				local root = _G
				local tbl = root

				for i, seg in ipairs(parts) do
					if type(tbl) ~= "table" and typeof and typeof(tbl) ~= "Instance" then
						return nil, nil, "Cannot index segment: " .. seg
					end
					local ok, child = pcall(function()
						if type(tbl) == "table" then
							return rawget(tbl, seg) or tbl[seg]
						else
							return tbl:FindFirstChild(seg) or tbl[seg]
						end
					end)
					if not ok or child == nil then
						return nil, nil, "Segment not found: " .. seg
					end
					tbl = child
				end

				if type(tbl) ~= "table" then
					return nil, nil, "Resolved path is not a table (got " .. type(tbl) .. ")"
				end
				return tbl, key, nil
			end

			local function evalValue(expr)
				if expr == "" or expr == "nil" then
					return true, nil
				end
				local fn, err = loadstring("return " .. expr)
				if not fn then
					return false, err
				end
				local ok, val = pcall(fn)
				if not ok then
					return false, tostring(val)
				end
				return true, val
			end

			local applyBtn = S:btn(
				cpanel,
				"Apply Patch",
				UDim2.fromOffset(100, 24),
				UDim2.fromOffset(4, 130),
				function()
					local valOk, newVal = evalValue(valBox.Text)
					if not valOk then
						setStatus(" Value eval: " .. tostring(newVal), true)
						return
					end

					if selectedPatchRef and tablePathBox.Text == "" then
						local patch = selectedPatchRef
						local key = tostring(patch.Key)
						local writeOk, writeErr = pcall(function()
							if setreadonly then
								setreadonly(patch.Table, false)
							elseif make_writeable then
								make_writeable(patch.Table)
							end
							rawset(patch.Table, patch.Key, newVal)
							if setreadonly then
								setreadonly(patch.Table, true)
							end
						end)
						if not writeOk then
							setStatus(" Write failed: " .. tostring(writeErr), true)
							return
						end
						patch.NewValue = newVal
						patch.Type = "manual_" .. type(newVal)
						patch.Frozen = freezeOnApply
						patch.RestoreOnRemove = restoreOriginal
						if freezeOnApply then
							S.FreezeList[selectedPatchId] = patch
							S:startFreezeLoop()
						else
							S.FreezeList[selectedPatchId] = nil
						end
						refreshPatches()
						setStatus(" [" .. key .. "] → " .. tostring(newVal):sub(1, 30), false)
						return
					end

					local tbl, key, resolveErr = resolvePatchTarget()
					if resolveErr then
						setStatus(" " .. resolveErr, true)
						return
					end

					local originalVal = rawget(tbl, key)

					local writeOk, writeErr = pcall(function()
						if setreadonly then
							setreadonly(tbl, false)
						elseif make_writeable then
							make_writeable(tbl)
						end
						rawset(tbl, key, newVal)
						if setreadonly then
							setreadonly(tbl, true)
						end
					end)
					if not writeOk then
						setStatus(" Write failed: " .. tostring(writeErr), true)
						return
					end

					local patchId = S:uid()
					local patchRecord = {
						ID = patchId,
						Table = tbl,
						Key = key,
						Original = originalVal,
						NewValue = newVal,
						Type = "manual_" .. type(newVal),
						Frozen = freezeOnApply,
						RestoreOnRemove = restoreOriginal,
						Timestamp = tick(),
						Active = true,
					}
					S.ActivePatches[patchId] = patchRecord

					if freezeOnApply then
						S.FreezeList[patchId] = patchRecord
						S:startFreezeLoop()
					end

					refreshPatches()
					setStatus(" Patched [" .. key .. "] → " .. tostring(newVal):sub(1, 30), false)
				end
			)
			applyBtn.BackgroundColor3 = Color3.fromRGB(30, 100, 55)
			applyBtn.Font = Enum.Font.SourceSansBold
			applyBtn.TextSize = 12

			local freezeModBtn = S:btn(
				cpanel,
				" Freeze Module",
				UDim2.fromOffset(120, 24),
				UDim2.fromOffset(108, 130),
				function()
					if not S.SelectedModule then
						setStatus(" No module selected in Explorer", true)
						return
					end
					local ok, mod = pcall(require, S.SelectedModule)
					if not ok or type(mod) ~= "table" then
						setStatus(" Module did not return a table", true)
						return
					end
					local count = 0
					local function deepFreeze(tbl, depth, prefix)
						if depth > 3 then
							return
						end
						for k, v in pairs(tbl) do
							local fullKey = prefix .. "." .. tostring(k)
							local pid = S:uid()
							local snap = v
							local patchRecord = {
								ID = pid,
								Table = tbl,
								Key = k,
								Original = v,
								NewValue = v,
								Type = "module_freeze",
								Frozen = true,
								RestoreOnRemove = true,
								Timestamp = tick(),
								Active = true,
							}
							S.ActivePatches[pid] = patchRecord
							S.FreezeList[pid] = patchRecord
							count = count + 1
							if type(v) == "table" then
								deepFreeze(v, depth + 1, fullKey)
							end
						end
					end
					deepFreeze(mod, 0, S.SelectedModule.Name)
					S:startFreezeLoop()
					refreshPatches()
					setStatus(" Froze " .. count .. " keys in " .. S.SelectedModule.Name, false)
				end
			)
			freezeModBtn.BackgroundColor3 = Color3.fromRGB(30, 70, 130)
			freezeModBtn.Font = Enum.Font.SourceSansBold
			freezeModBtn.TextSize = 11

			local gcBtn = S:btn(
				cpanel,
				" Patch via GC",
				UDim2.fromOffset(110, 24),
				UDim2.fromOffset(232, 130),
				function()
					local key = keyBox.Text
					if key == "" then
						setStatus(" Key required for GC scan", true)
						return
					end
					if not getgc then
						setStatus(" getgc() not available in this executor", true)
						return
					end
					local valOk, newVal = evalValue(valBox.Text)
					if not valOk then
						setStatus(" Value eval: " .. tostring(newVal), true)
						return
					end

					local found = 0
					local ok2, gc = pcall(getgc, true)
					if not ok2 then
						setStatus(" getgc() failed", true)
						return
					end
					for _, v in ipairs(gc) do
						if type(v) == "table" and rawget(v, key) ~= nil then
							local originalVal = rawget(v, key)
							local wOk = pcall(function()
								if setreadonly then
									setreadonly(v, false)
								elseif make_writeable then
									make_writeable(v)
								end
								rawset(v, key, newVal)
								if setreadonly then
									setreadonly(v, true)
								end
							end)
							if wOk then
								local pid = S:uid()
								local pr = {
									ID = pid,
									Table = v,
									Key = key,
									Original = originalVal,
									NewValue = newVal,
									Type = "gc_patch",
									Frozen = freezeOnApply,
									RestoreOnRemove = restoreOriginal,
									Timestamp = tick(),
									Active = true,
								}
								S.ActivePatches[pid] = pr
								if freezeOnApply then
									S.FreezeList[pid] = pr
									S:startFreezeLoop()
								end
								found = found + 1
							end
						end
					end
					refreshPatches()
					if found > 0 then
						setStatus(" GC patched " .. found .. " table(s) with key [" .. key .. "]", false)
					else
						setStatus(" No GC tables found with key: " .. key, true)
					end
				end
			)
			gcBtn.BackgroundColor3 = Color3.fromRGB(80, 50, 20)
			gcBtn.Font = Enum.Font.SourceSansBold
			gcBtn.TextSize = 11

			local hintLbl = Instance.new("TextLabel", cpanel)
			hintLbl.Size = UDim2.new(1, -8, 0, 26)
			hintLbl.Position = UDim2.fromOffset(4, 160)
			hintLbl.BackgroundTransparency = 1
			hintLbl.TextColor3 = S:subtext()
			hintLbl.Font = Enum.Font.Code
			hintLbl.TextSize = 9
			hintLbl.TextWrapped = true
			hintLbl.TextXAlignment = Enum.TextXAlignment.Left
			hintLbl.Text =
				"Tips: Table Path blank = use Explorer selection. Value supports any Lua expression.  Freeze Module snapshots all keys.  GC scan patches every table in heap owning that key."

			PM.Refresh = refreshPatches
			refreshPatches()
			return PM
		end

		return { InitDeps = initDeps, InitAfterMain = initAfterMain, Main = main }
	end,
	["RemoteSpy"] = function()
		local Main, Lib, Apps, Settings
		local env, service, plr

		local function initDeps(data)
			Main = data.Main
			Lib = data.Lib
			Apps = data.Apps
			Settings = data.Settings
			env = data.env
			service = data.service
			plr = data.plr
		end

		local function initAfterMain() end

		local function main()
			local RemoteSpy = {}

			-- Fake Window object so Dex's CreateApp can Show/Hide us
			local fakeWindow = {}
			local spyLaunched = false
			local spyGui = nil -- reference to ui.SimpleSpy3 once launched

			local function launchSpy()
				-- Run SimpleSpy in a sandboxed pcall, capturing the ScreenGui it creates
				local ok, err = pcall(function()
					if getgenv().SimpleSpyExecuted and type(getgenv().SimpleSpyShutdown) == "function" then
						getgenv().SimpleSpyShutdown()
					end

					local realconfigs = {
						logcheckcaller = false,
						autoblock = false,
						funcEnabled = true,
						advancedinfo = false,
						--logreturnvalues = false,
						supersecretdevtoggle = false,
						log_FireServer = true,
						log_InvokeServer = true,
						log_Fire = true,
						log_Invoke = true,
						bufferDumpComments = false,
						log_Receive = true,
						adonisBypass = true,
						pathMode = 1,
						blockIncoming = true,
						ignorePlayerModule = false,
					}

					local configs = newproxy(true)
					local configsmetatable = getmetatable(configs)

					configsmetatable.__index = function(self, index)
						return realconfigs[index]
					end

					local oth = syn and syn.oth
					local unhook = oth and oth.unhook
					local hook = oth and oth.hook

					local lower = string.lower
					local byte = string.byte
					local round = math.round
					local running = coroutine.running
					local resume = coroutine.resume
					local status = coroutine.status
					local yield = coroutine.yield
					local create = coroutine.create
					local close = coroutine.close
					local OldDebugId = game.GetDebugId
					local info = debug.info
					local getregistry = (debug and debug.getregistry) or getreg
					local getreg = getreg or getregistry

					local function safeDebugInfo(target, what)
						if not info then
							return nil
						end

						local ok, result = pcall(info, target, what)
						return ok and result or nil
					end

					local function safeGetScriptFromThread(thread)
						if not getscriptfromthread or not thread then
							return nil
						end

						local ok, script = pcall(getscriptfromthread, thread)
						return ok and script or nil
					end

					local IsA = game.IsA
					local tostring = tostring
					local tonumber = tonumber
					local delay = task.delay
					local spawn = task.spawn
					local clear = table.clear
					local clone = table.clone

					local function blankfunction(...)
						return ...
					end

					local get_thread_identity = (syn and syn.get_thread_identity) or getidentity or getthreadidentity
					local set_thread_identity = (syn and syn.set_thread_identity) or setidentity
					local islclosure = islclosure or is_l_closure
					local threadfuncs = (get_thread_identity and set_thread_identity and true) or false

					local getinfo = getinfo or blankfunction
					local getupvalues = getupvalues or debug.getupvalues or blankfunction
					local getconstants = getconstants or debug.getconstants or blankfunction

					local getcustomasset = getsynasset or getcustomasset
					local getcallingscript = getcallingscript or blankfunction
					local newcclosure = newcclosure or blankfunction
					local clonefunction = clonefunction or blankfunction
					local cloneref = cloneref or blankfunction
					local request = request or syn and syn.request
					local isfunctionhooked = isfunctionhooked
					local makewritable = makewriteable or function(tbl)
						setreadonly(tbl, false)
					end
					local makereadonly = makereadonly or function(tbl)
						setreadonly(tbl, true)
					end
					local isreadonly = isreadonly or table.isfrozen

					local setclipboard = setclipboard
						or toclipboard
						or set_clipboard
						or (Clipboard and Clipboard.set)
						or function(...)
							return ErrorPrompt("Attempted to set clipboard: " .. (...), true)
						end

					local hookmetamethod = hookmetamethod
						or (makewriteable and makereadonly and getrawmetatable)
							and function(obj: object, metamethod: string, func: Function)
								local old = getrawmetatable(obj)

								if hookfunction then
									return hookfunction(old[metamethod], func)
								else
									local oldmetamethod = old[metamethod]
									makewriteable(old)
									old[metamethod] = func
									makereadonly(old)
									return oldmetamethod
								end
							end

					local function Create(instance, properties, children)
						local obj = Instance.new(instance)

						for i, v in next, properties or {} do
							obj[i] = v
							for _, child in next, children or {} do
								child.Parent = obj
							end
						end
						return obj
					end

					local function SafeGetService(name)
						local Service = game.GetService
						local Reference = cloneref or function(reference)
							return reference
						end
						return Reference(Service(game, name))
					end

					local function protectUI(sGui)
						if sGui:IsA("ScreenGui") then
							sGui.ZIndexBehavior = Enum.ZIndexBehavior.Global
							sGui.DisplayOrder = 999999999
							sGui.ResetOnSpawn = false
							--sGui.IgnoreGuiInset = true
						end
						local cGUI = SafeGetService("CoreGui")
						local lPlr = SafeGetService("Players").LocalPlayer

						local function NAProtection(inst, var)
							if inst then
								if var then
									inst[var] = "\0"
									inst.Archivable = false
								else
									inst.Name = "\0"
									inst.Archivable = false
								end
							end
						end

						if gethui then
							NAProtection(sGui)
							sGui.Parent = gethui()
							return sGui
						elseif cGUI and cGUI:FindFirstChild("RobloxGui") then
							NAProtection(sGui)
							sGui.Parent = cGUI:FindFirstChild("RobloxGui")
							return sGui
						elseif cGUI then
							NAProtection(sGui)
							sGui.Parent = cGUI
							return sGui
						elseif lPlr and lPlr:FindFirstChildWhichIsA("PlayerGui") then
							NAProtection(sGui)
							sGui.Parent = lPlr:FindFirstChildWhichIsA("PlayerGui")
							sGui.ResetOnSpawn = false
							return sGui
						else
							return nil
						end
					end

					local adonisThreads = {}
					local function detectAdonis()
						if not getreg or not getgc then
							return false
						end

						local detected = false
						for _, thread in getreg() do
							if type(thread) ~= "thread" then
								continue
							end
							local src = safeDebugInfo(thread, "s")
							if src and (src:find(".Core.Anti") or src:find(".Plugins.Anti_Cheat")) then
								detected = true
								table.insert(adonisThreads, thread)
							end
						end
						return detected
					end

					local function hookAdonisDetections(adonisTables)
						for _, t in ipairs(adonisTables) do
							for _, fn in pairs(t) do
								if type(fn) ~= "function" then
									continue
								end
								if isfunctionhooked and isfunctionhooked(fn) then
									continue
								end

								local function blocker(...)
									coroutine.yield(coroutine.running())
									return task.wait(9e9)
								end

								if hookfunction then
									pcall(hookfunction, fn, blocker)
								elseif hook then
									pcall(hook, fn, clonefunction and clonefunction(blocker) or blocker)
								end
							end
						end
					end

					local function bypassAdonis()
						for _, thread in ipairs(adonisThreads) do
							pcall(close, thread)
						end

						local adonisTables = {}
						if filtergc then
							local ok, cont = pcall(filtergc, "table", { Keys = { "Detected", "RLocked" } }, false)
							if ok and type(cont) == "table" then
								for _, tbl in ipairs(cont) do
									if typeof(rawget(tbl, "Detected")) == "function" then
										table.insert(adonisTables, tbl)
									end
								end
							end
						end

						if #adonisTables == 0 and getgc then
							for _, tbl in ipairs(getgc(true)) do
								if type(tbl) ~= "table" then
									continue
								end
								local detectFn = rawget(tbl, "Detected")
								if typeof(detectFn) == "function" and rawget(tbl, "RLocked") then
									table.insert(adonisTables, tbl)
								end
							end
						end

						hookAdonisDetections(adonisTables)
					end

					local function runAdonisBypass()
						if not configs.adonisBypass or getgenv().SimpleSpyAdonisBypassed then
							return
						end
						local detected = false
						local ok, res = pcall(detectAdonis)
						detected = ok and res or false
						if detected then
							bypassAdonis()
							getgenv().SimpleSpyAdonisBypassed = true
						end
					end

					local function Search(logtable, tbl)
						table.insert(logtable, tbl)

						for i, v in tbl do
							if type(v) == "table" then
								return table.find(logtable, v) ~= nil or Search(v)
							end
						end
					end

					local function IsCyclicTable(tbl)
						local checkedtables = {}

						local function SearchTable(tbl)
							table.insert(checkedtables, tbl)

							for i, v in next, tbl do -- Stupid mistake on my part thanks 59it for pointing it out
								if type(v) == "table" then
									return table.find(checkedtables, v) and true or SearchTable(v)
								end
							end
						end

						return SearchTable(tbl)
					end

					local function deepclone(args: table, copies: table): table
						local copy = nil
						copies = copies or {}

						if type(args) == "table" then
							if copies[args] then
								copy = copies[args]
							else
								copy = {}
								copies[args] = copy
								for i, v in next, args do
									copy[deepclone(i, copies)] = deepclone(v, copies)
								end
							end
						elseif typeof(args) == "Instance" then
							copy = cloneref(args)
						else
							copy = args
						end
						return copy
					end

					local function rawtostring(userdata)
						if type(userdata) == "table" or typeof(userdata) == "userdata" then
							local rawmetatable = getrawmetatable(userdata)
							local cachedstring = rawmetatable and rawget(rawmetatable, "__tostring")

							if cachedstring then
								local wasreadonly = isreadonly(rawmetatable)
								if wasreadonly then
									makewritable(rawmetatable)
								end
								rawset(rawmetatable, "__tostring", nil)
								local safestring = tostring(userdata)
								rawset(rawmetatable, "__tostring", cachedstring)
								if wasreadonly then
									makereadonly(rawmetatable)
								end
								return safestring
							end
						end
						return tostring(userdata)
					end

