						local function findSpyGui()
							local searchRoots = {}
							if gethui then
								table.insert(searchRoots, gethui())
							end
							table.insert(searchRoots, game:GetService("CoreGui"))
							local lp = game:GetService("Players").LocalPlayer
							if lp then
								local pg = lp:FindFirstChildOfClass("PlayerGui")
								if pg then
									table.insert(searchRoots, pg)
								end
							end
							for _, root in ipairs(searchRoots) do
								for _, child in ipairs(root:GetChildren()) do
									-- SimpleSpy renames its gui to '\0' for protection
									if child:IsA("ScreenGui") and child:FindFirstChild("Background", true) then
										return child
									end
								end
							end
						end
						spyGui = findSpyGui()
					end
				end)
				if ok then
					spyLaunched = true
				else
					warn("[RemoteSpy] Failed to launch SimpleSpy: " .. tostring(err))
				end
			end

			function fakeWindow:Show()
				if not spyLaunched then
					launchSpy()
				elseif spyGui then
					spyGui.Enabled = true
				elseif getgenv().SimpleSpyShutdown then
					-- already running, just re-show via its own toggle
					if getgenv().SimpleSpyExecuted then
						local bg = spyGui and spyGui:FindFirstChild("Background")
						if bg then
							bg.Visible = true
						end
					end
				end
			end

			function fakeWindow:Hide()
				if spyGui then
					spyGui.Enabled = false
				elseif getgenv().SimpleSpyExecuted then
					-- find and hide
					local function findAndHide(root)
						for _, child in ipairs(root:GetChildren()) do
							if child:IsA("ScreenGui") and child:FindFirstChild("Background", true) then
								child.Enabled = false
								spyGui = child
								return
							end
						end
					end
					if gethui then
						findAndHide(gethui())
					end
					findAndHide(game:GetService("CoreGui"))
					local lp = game:GetService("Players").LocalPlayer
					if lp then
						local pg = lp:FindFirstChildOfClass("PlayerGui")
						if pg then
							findAndHide(pg)
						end
					end
				end
			end

			-- OnActivate/OnDeactivate stubs so Dex doesn't error
			fakeWindow.OnActivate = Instance.new("BindableEvent").Event
			fakeWindow.OnDeactivate = Instance.new("BindableEvent").Event

			RemoteSpy.Window = fakeWindow
			return RemoteSpy
		end

		return { InitDeps = initDeps, InitAfterMain = initAfterMain, Main = main }
	end,
}
local oldgame = oldgame or game

cloneref = cloneref
	or function(ref)
		if not getreg then
			return ref
		end

		local InstanceList

		local a = Instance.new("Part")
		for _, c in pairs(getreg()) do
			if type(c) == "table" and #c then
				if rawget(c, "__mode") == "kvs" then
					for d, e in pairs(c) do
						if e == a then
							InstanceList = c
							break
						end
					end
				end
			end
		end
		local f = {}
		function f.invalidate(g)
			if not InstanceList then
				return
			end
			for b, c in pairs(InstanceList) do
				if c == g then
					InstanceList[b] = nil
					return g
				end
			end
		end
		return f.invalidate
	end

